```typescript
import { KlaviyoUpdatePayload, KlaviyoUserProfileWithEmail } from './types';
import { AmpError, ErrorType } from '@amp/shared/errors/amp-error';
import { AmpErrorName } from '@amp/shared/errors/amp-error-name';
import { getKlaviyoApiKeyPath } from '@amp/backend-shared/utils/env/envUtility';
import { getSecretsValuesFor } from '@amp/core/utils/secrets-utils';
import { createKlaviyoClient } from './klaviyo-client';
import { logger } from '@amp/core/utils/logger';
import pRetry, { AbortError } from 'p-retry';
import { isRetryableKlaviyoError } from './utils';

const RETRY_OPTIONS: pRetry.Options = {
    retries: 3,
    factor: 2,
    minTimeout: 1_000,
    maxTimeout: 10_000,
    onFailedAttempt: (error) => {
        logger.warn(`Klaviyo API attempt ${error.attemptNumber} failed. ${error.retriesLeft} retries left.`);
    },
};

export async function updateKlaviyo(
    hashedAmpUserId: string,
    payload: KlaviyoUpdatePayload,
    userProfile: KlaviyoUserProfileWithEmail,
): Promise<void> {
    const [apiKey] = await getSecretsValuesFor([getKlaviyoApiKeyPath()]);
    if (!apiKey) {
        throw new AmpError({
            name: AmpErrorName.KlaviyoAPIKeyNotFoundError,
            message: 'Klaviyo API key not found in SSM',
            type: ErrorType.SystemError,
        });
    }

    const klaviyoClient = createKlaviyoClient(apiKey);

    const { events, ...profileProperties } = payload;

    await pRetry(
        async () => {
            try {
                await klaviyoClient.updateUser(hashedAmpUserId, profileProperties, userProfile);
            } catch (error) {
                if (isRetryableKlaviyoError(error)) throw error;
                throw new AbortError(error instanceof Error ? error.message : String(error));
            }
        },
        RETRY_OPTIONS,
    );

    if (events?.length) {
        logger.info(`Tracking ${events.length} events`);

        for (const [index, event] of events.entries()) {
            logger.info(`Tracking event: ${index + 1} of ${events.length}`);
            await pRetry(
                async () => {
                    try {
                        await klaviyoClient.trackEvent(hashedAmpUserId, 'Workout Completed', userProfile, event);
                    } catch (error) {
                        if (isRetryableKlaviyoError(error)) throw error;
                        throw new AbortError(error instanceof Error ? error.message : String(error));
                    }
                },
                RETRY_OPTIONS,
            );
        }
    }
}
```

